from pathlib import Path
import re
import requests
from urllib.parse import urlparse

ROOT = Path(__file__).resolve().parent.parent
DATA_DIR = ROOT / "data"
DATA_DIR.mkdir(parents=True, exist_ok=True)

# Источники для объединения в custom-ru
SOURCES = {
    "custom-ru": [
        # antifilter-download-community: замени на нужный raw URL списка доменов
        "https://raw.githubusercontent.com/anticensority/runet-censorship-bypass/main/generated/domains.lst",
        # Re-filter-lists
        "https://raw.githubusercontent.com/1andrevich/Re-filter-lists/main/domains_all.lst",
    ],
    # category-ads: здесь пока берём ручной список в MANUAL ниже
    "category-ads": [],
}

